components.js_init:
import * as THREE from 'https://unpkg.com/three@0.158.0/build/three.module.js';
const canvas = document.getElementById('three-canvas');
const renderer = new THREE.WebGLRenderer({ canvas, alpha: true, antialias: true });
renderer.setSize(window.innerWidth, window.innerHeight);
renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
const scene = new THREE.Scene();
const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
camera.position.z = 5;
const torusGeo = new THREE.TorusKnotGeometry({{torusRadius}}, {{torusTube}}, 128, 32);
const torusMat = new THREE.MeshBasicMaterial({ color: {{wireframeColor}}, wireframe: true, transparent: true, opacity: {{wireframeOpacity}} });
const torusKnot = new THREE.Mesh(torusGeo, torusMat);
scene.add(torusKnot);
const particleCount = {{particleCount}};
const positions = new Float32Array(particleCount * 3);
const colors = new Float32Array(particleCount * 3);
const c1 = new THREE.Color({{particleColor1}});
const c2 = new THREE.Color({{particleColor2}});
for (let i = 0; i < particleCount; i++) {
  positions[i*3] = (Math.random()-0.5)*20;
  positions[i*3+1] = (Math.random()-0.5)*20;
  positions[i*3+2] = (Math.random()-0.5)*20;
  const t = Math.random();
  const col = c1.clone().lerp(c2, t);
  colors[i*3] = col.r; colors[i*3+1] = col.g; colors[i*3+2] = col.b;
}
const particleGeo = new THREE.BufferGeometry();
particleGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
particleGeo.setAttribute('color', new THREE.BufferAttribute(colors, 3));
const particleMat = new THREE.PointsMaterial({ size: 0.025, vertexColors: true, transparent: true, opacity: 0.6, sizeAttenuation: true });
const particles = new THREE.Points(particleGeo, particleMat);
scene.add(particles);
let mouseX = 0, mouseY = 0;
document.addEventListener('mousemove', (e) => { mouseX = (e.clientX/window.innerWidth - 0.5)*2; mouseY = (e.clientY/window.innerHeight - 0.5)*2; });
function animate() {
  requestAnimationFrame(animate);
  torusKnot.rotation.x += 0.003; torusKnot.rotation.y += 0.005;
  torusKnot.position.x += (mouseX*0.5 - torusKnot.position.x)*0.02;
  torusKnot.position.y += (-mouseY*0.5 - torusKnot.position.y)*0.02;
  particles.rotation.y += 0.0003; particles.rotation.x += 0.0001;
  camera.position.x += (mouseX*0.3 - camera.position.x)*0.01;
  camera.position.y += (-mouseY*0.3 - camera.position.y)*0.01;
  camera.lookAt(scene.position);
  renderer.render(scene, camera);
}
animate();
window.addEventListener('resize', () => { camera.aspect = window.innerWidth/window.innerHeight; camera.updateProjectionMatrix(); renderer.setSize(window.innerWidth, window.innerHeight); });

