components.css:
.stat-card { background: linear-gradient(135deg, rgba(18,18,26,0.9), rgba(26,26,46,0.6)); border: 1px solid var(--border); border-radius: 16px; padding: 32px 24px; text-align: center; position: relative; overflow: hidden; backdrop-filter: blur(10px); }
.stat-card::before { content: ''; position: absolute; top: 0; left: 0; right: 0; height: 2px; background: linear-gradient(90deg, {{accentColor1}}, {{accentColor2}}); }
.stat-number { font-size: 42px; font-weight: 900; color: {{numberColor}}; line-height: 1; margin-bottom: 8px; letter-spacing: -1px; }
.stat-label { font-size: 14px; color: var(--text-dim); font-weight: 500; }
.stat-shimmer { position: absolute; inset: 0; background: linear-gradient(90deg, transparent 25%, rgba(255,255,255,0.03) 50%, transparent 75%); background-size: 200% 100%; animation: shimmer 2s infinite; }
@keyframes shimmer { 0% { background-position: 200% 0; } 100% { background-position: -200% 0; } }

components.js_init:
gsap.registerPlugin(ScrollTrigger);
let triggered = false;
ScrollTrigger.create({
  trigger: '{{triggerSelector}}',
  start: 'top 80%',
  onEnter: () => {
    if (triggered) return;
    triggered = true;
    document.querySelectorAll('.stat-shimmer').forEach(s => gsap.to(s, { opacity: 0, duration: 0.5, onComplete: () => s.remove() }));
    document.querySelectorAll('.stat-number').forEach(el => {
      const raw = el.dataset.count;
      const prefix = el.dataset.prefix || '';
      const suffix = el.dataset.suffix || '';
      const target = parseFloat(raw);
      const isDecimal = raw.includes('.');
      gsap.to({ val: 0 }, {
        val: target, duration: {{duration}}, ease: 'power2.out',
        onUpdate: function() {
          const v = this.targets()[0].val;
          el.textContent = prefix + (isDecimal ? v.toFixed(1) : Math.floor(v).toLocaleString('{{locale}}')) + suffix;
        }
      });
    });
  }
});

components.css:
.card-3d-wrapper { perspective: 1000px; cursor: pointer; }
.card-3d { background: linear-gradient(145deg, rgba(18,18,26,0.95), rgba(10,10,15,0.95)); border: 1px solid var(--border); border-radius: 20px; padding: 40px 32px; position: relative; overflow: hidden; transition: transform 0.3s ease, box-shadow 0.3s ease; transform-style: preserve-3d; will-change: transform; }
.card-3d:hover { box-shadow: 0 20px 60px rgba(0,0,0,0.4), 0 0 30px rgba(59,130,246,0.1); }
.card-3d-glow { position: absolute; width: 300px; height: 300px; border-radius: 50%; background: radial-gradient(circle, {{glowColor}}, transparent 70%); pointer-events: none; opacity: 0; transition: opacity 0.3s; transform: translate(-50%, -50%); }
.card-3d:hover .card-3d-glow { opacity: 1; }
.card-3d-icon { width: 56px; height: 56px; border-radius: 14px; display: flex; align-items: center; justify-content: center; font-size: 24px; margin-bottom: 24px; position: relative; z-index: 1; }
.card-3d h3 { font-size: 22px; font-weight: 700; color: var(--text-bright); margin-bottom: 12px; position: relative; z-index: 1; }
.card-3d p { font-size: 15px; color: var(--text-dim); line-height: 1.7; position: relative; z-index: 1; }
.card-3d-tag { display: inline-block; margin-top: 20px; padding: 4px 12px; border-radius: 20px; font-size: 12px; font-weight: 600; position: relative; z-index: 1; }

components.js_init:
document.querySelectorAll('.card-3d-wrapper').forEach(wrapper => {
  const card = wrapper.querySelector('.card-3d');
  const glow = card.querySelector('.card-3d-glow');
  wrapper.addEventListener('mousemove', (e) => {
    const rect = wrapper.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;
    const centerX = rect.width / 2;
    const centerY = rect.height / 2;
    const rotateX = (y - centerY) / centerY * -{{maxTilt}};
    const rotateY = (x - centerX) / centerX * {{maxTilt}};
    card.style.transform = `perspective(1000px) rotateX(${rotateX}deg) rotateY(${rotateY}deg) translateZ(20px)`;
    if (glow) { glow.style.left = x + 'px'; glow.style.top = y + 'px'; }
  });
  wrapper.addEventListener('mouseleave', () => {
    card.style.transform = 'perspective(1000px) rotateX(0) rotateY(0) translateZ(0)';
  });
});

components.css:
.flip-words-wrapper { display: inline-block; position: relative; height: 1.1em; overflow: hidden; vertical-align: bottom; }
.flip-words-inner { display: flex; flex-direction: column; animation: flipWord {{cycleDuration}} infinite; }
.flip-word { height: 1.1em; display: flex; align-items: center; background: linear-gradient(135deg, {{gradientStart}}, {{gradientEnd}}); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; }
@keyframes flipWord { 0%, 20% { transform: translateY(0); } 25%, 45% { transform: translateY(-1.1em); } 50%, 70% { transform: translateY(-2.2em); } 75%, 95% { transform: translateY(-3.3em); } 100% { transform: translateY(-4.4em); } }

.meteors-container { position: absolute; inset: 0; overflow: hidden; pointer-events: none; }
.meteor { position: absolute; width: 150px; height: 1px; background: linear-gradient(90deg, {{trailColor}}, transparent); transform: rotate(-45deg); animation: meteorFall linear infinite; opacity: 0; filter: drop-shadow(0 0 4px {{glowColor}}); }
