.meteor:nth-child(2) { top: 15%; left: 85%; animation-duration: 2.5s; animation-delay: 0.8s; width: 100px; }
.meteor:nth-child(3) { top: 8%; left: 50%; animation-duration: 3.5s; animation-delay: 1.5s; width: 180px; }
.meteor:nth-child(4) { top: 25%; left: 90%; animation-duration: 2.8s; animation-delay: 2.2s; width: 90px; }
.meteor:nth-child(5) { top: 2%; left: 60%; animation-duration: 4s; animation-delay: 0.4s; width: 140px; }
.meteor:nth-child(6) { top: 20%; left: 75%; animation-duration: 3.2s; animation-delay: 3s; width: 110px; }
.meteor:nth-child(7) { top: 12%; left: 95%; animation-duration: 2.6s; animation-delay: 1.8s; width: 160px; }
.meteor:nth-child(8) { top: 30%; left: 80%; animation-duration: 3.8s; animation-delay: 2.6s; width: 130px; }
.meteor:nth-child(9) { top: -2%; left: 45%; animation-duration: 3.3s; animation-delay: 4s; width: 100px; }
.meteor:nth-child(10) { top: 18%; left: 55%; animation-duration: 2.9s; animation-delay: 3.4s; width: 170px; }

.stars-container { position: absolute; inset: 0; overflow: hidden; pointer-events: none; }
.star { position: absolute; width: 2px; height: 2px; background: white; border-radius: 50%; animation: starGlow 3s ease-in-out infinite; }
@keyframes starGlow { 0%, 100% { opacity: 0.2; box-shadow: 0 0 4px {{glowColor1}}; } 50% { opacity: 0.8; box-shadow: 0 0 12px {{glowColor2}}; } }

components.js_init:
(function() {
  const container = document.getElementById('{{containerId}}');
  for (let i = 0; i < {{starCount}}; i++) {
    const star = document.createElement('div');
    star.className = 'star';
    star.style.cssText = `left:${Math.random()*100}%; top:${Math.random()*100}%; animation-delay:${Math.random()*3}s; animation-duration:${Math.random()*2+2}s; width:${Math.random()*2+1}px; height:${Math.random()*2+1}px;`;
    container.appendChild(star);
  }
})();

components.css:
.moving-border-card { position: relative; border-radius: 20px; overflow: hidden; }
.moving-border { position: absolute; inset: -2px; border-radius: 22px; z-index: -1; overflow: hidden; }
.moving-border::before { content: ''; position: absolute; inset: -50%; background: conic-gradient(from 0deg, transparent, {{color1}}, {{color2}}, {{color3}}, transparent); animation: rotateBorder {{speed}} linear infinite; }
@keyframes rotateBorder { to { transform: rotate(360deg); } }
.moving-border::after { content: ''; position: absolute; inset: {{borderWidth}}; background: linear-gradient(145deg, rgba(18,18,26,0.98), rgba(10,10,15,0.98)); border-radius: 20px; }

@property --border-beam-angle { syntax: '<angle>'; initial-value: 0deg; inherits: false; }
.border-beam-card { position: relative; border-radius: 20px; }
.border-beam-card::after { content: ''; position: absolute; inset: -2px; border-radius: 22px; background: conic-gradient(from var(--border-beam-angle, 0deg), transparent 60%, {{color1}}, {{color2}}, transparent 100%); z-index: -1; animation: borderBeam {{speed}} linear infinite; }
@keyframes borderBeam { to { --border-beam-angle: 360deg; } }

components.js_init:
(function() {
  const container = document.getElementById('{{containerId}}');
  const colors = [{{colors}}];
  for (let i = 0; i < {{count}}; i++) {
    const p = document.createElement('div');
    p.className = 'floating-particle';
    const size = Math.random() * {{maxSize}} + {{minSize}};
    const color = colors[Math.floor(Math.random() * colors.length)];
    p.style.cssText = `width:${size}px; height:${size}px; left:${Math.random()*100}%; background:${color}; box-shadow:0 0 ${size*4}px ${color}; animation-duration:${Math.random()*15+10}s; animation-delay:${Math.random()*-20}s;`;
    container.appendChild(p);
  }
})();

components.css:
.glass-btn { position: relative; display: inline-flex; align-items: center; gap: 10px; padding: {{padding}}; border-radius: 50px; font-family: 'Inter', sans-serif; font-size: {{fontSize}}; font-weight: 600; text-decoration: none; cursor: pointer; border: none; overflow: hidden; transition: all 0.4s cubic-bezier(0.25, 0.46, 0.45, 0.94); }
.glass-btn-primary { background: linear-gradient(135deg, {{primaryBg1}}, {{primaryBg2}}); color: white; backdrop-filter: saturate(180%) blur(20px); -webkit-backdrop-filter: saturate(180%) blur(20px); border: 1px solid rgba(255,255,255,0.15); box-shadow: 0 8px 32px {{primaryShadow}}, inset 0 1px 0 rgba(255,255,255,0.15); }
.glass-btn-primary:hover { box-shadow: 0 8px 40px {{primaryHoverShadow}}, 0 0 20px {{primaryHoverGlow}}, inset 0 1px 0 rgba(255,255,255,0.2); transform: translateY(-2px); }
.glass-btn-secondary { background: rgba(255,255,255,0.05); color: var(--text); backdrop-filter: saturate(180%) blur(20px); -webkit-backdrop-filter: saturate(180%) blur(20px); border: 1px solid rgba(255,255,255,0.1); }
.glass-btn-secondary:hover { background: rgba(255,255,255,0.1); border-color: rgba(255,255,255,0.2); transform: translateY(-2px); }
.glass-btn::after { content: ''; position: absolute; top: 0; left: -100%; width: 100%; height: 100%; background: linear-gradient(90deg, transparent, rgba(255,255,255,0.15), transparent); transition: left 0.5s ease; }
.glass-btn:hover::after { left: 100%; }
.magnetic-area { display: inline-block; transition: transform 0.2s ease-out; }

components.js_init:
document.querySelectorAll('.magnetic-area').forEach(area => {
  area.addEventListener('mousemove', (e) => {
    const rect = area.getBoundingClientRect();
    const x = e.clientX - rect.left - rect.width/2;
    const y = e.clientY - rect.top - rect.height/2;
    area.style.transform = `translate(${x*{{magnetStrength}}}px, ${y*{{magnetStrength}}}px)`;
  });
  area.addEventListener('mouseleave', () => { area.style.transform = 'translate(0, 0)'; });
});

